/**
 * FHIR Bundle → PhpData mapper.
 * Reads a PCO IG collection Bundle (as generated by fhir-builder.ts)
 * and reconstructs a PhpData object suitable for PDF generation.
 *
 * Fields not represented in the bundle (values, vision, strengths,
 * discharge_plan, is_final_session) will be absent from the PDF.
 */
// ---------------------------------------------------------------------------
// Constants (mirrors fhir-builder.ts)
// ---------------------------------------------------------------------------
const SNOMED_SYSTEM = "http://snomed.info/sct";
const WHAT_MATTERS_CODE = "247751003";
const WBS_SYSTEM = "http://mtnlotus.com/fhir/whole-health-cards/CodeSystem/well-being-signs";
const WBS_PANEL_CODE = "well-being-signs";
const PCO_READINESS_PROFILE = "http://hl7.org/fhir/us/pco/StructureDefinition/pco-readiness-assessment";
const PERTAINSTOGOAL_URL = "http://hl7.org/fhir/StructureDefinition/resource-pertainsToGoal";
// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
function reverseStatus(status) {
    const mapping = {
        completed: "met",
        stopped: "not-met",
        active: "in-progress",
    };
    return mapping[status ?? ""] ?? "in-progress";
}
/**
 * Parse the MAP Observation valueString back into structured fields.
 * The builder encodes: "Mission: X Aspiration: Y Purpose: Z narrative"
 * When no labeled fields are present, the whole string is what_matters_most.
 */
function parseMapValueString(text) {
    const hasMission = /Mission:/i.test(text);
    const hasAspiration = /Aspiration:/i.test(text);
    const hasPurpose = /Purpose:/i.test(text);
    if (!hasMission && !hasAspiration && !hasPurpose) {
        return { what_matters_most: text };
    }
    // Extract each labeled segment; each runs until the next label or end of string
    const mission = text.match(/Mission:\s*(.*?)(?=\s+Aspiration:|\s+Purpose:|$)/si)?.[1]?.trim();
    const aspiration = text.match(/Aspiration:\s*(.*?)(?=\s+Purpose:|$)/si)?.[1]?.trim();
    // Purpose runs to end; we can't separate it from a trailing narrative
    const purpose = text.match(/Purpose:\s*(.*)/si)?.[1]?.trim();
    const map = (mission || aspiration || purpose)
        ? { mission, aspiration, purpose }
        : undefined;
    return { map };
}
// ---------------------------------------------------------------------------
// Bundle → PhpData
// ---------------------------------------------------------------------------
/**
 * Reconstruct a PhpData object from a FHIR Bundle generated by fhir-builder.ts.
 *
 * Fields not encoded in the bundle (values, vision, strengths, discharge_plan,
 * is_final_session) are omitted and the corresponding PDF sections will be blank.
 */
export function bundleToPhpData(bundle) {
    const entries = bundle.entry ?? [];
    // Index entries by fullUrl for reference resolution
    const byUrl = new Map();
    for (const e of entries) {
        byUrl.set(e.fullUrl, e.resource);
    }
    let patient;
    let sessionDate;
    let map;
    let what_matters_most;
    let wbs;
    // Goals are indexed by fullUrl so Readiness and ServiceRequest can reference them.
    const goals = [];
    const goalIdxByUrl = new Map();
    // Pass 1 — Goals (must be indexed before Observation/ServiceRequest references)
    for (const entry of entries) {
        const r = entry.resource;
        if (r.resourceType === "Goal") {
            const goal = {
                text: r.description?.text ?? "",
                lifecycle_status: r.lifecycleStatus ?? "active",
                start_date: r.startDate,
                action_steps: [],
            };
            goalIdxByUrl.set(entry.fullUrl, goals.length);
            goals.push(goal);
        }
    }
    // Pass 2 — Patient, Observations, ServiceRequests
    for (const entry of entries) {
        const r = entry.resource;
        if (r.resourceType === "Patient") {
            const name = r.name?.[0];
            patient = {
                family: name?.family ?? "",
                given: name?.given ?? [],
                birth_date: r.birthDate,
            };
        }
        else if (r.resourceType === "Observation") {
            const isReadiness = r.meta?.profile?.includes(PCO_READINESS_PROFILE);
            const codeSystem = r.code?.coding?.[0]?.system;
            const codeCode = r.code?.coding?.[0]?.code;
            if (isReadiness) {
                // Attach readiness scores and rationale to the referenced goal.
                // Most-recent-wins: later observations overwrite earlier ones.
                const goalUrl = r.focus?.[0]?.reference;
                const goalIdx = goalUrl !== undefined ? goalIdxByUrl.get(goalUrl) : undefined;
                if (goalIdx !== undefined) {
                    const goal = goals[goalIdx];
                    for (const comp of r.component ?? []) {
                        const code = comp.code.coding?.[0]?.code;
                        if (code === "importance" && comp.valueInteger !== undefined)
                            goal.importance = comp.valueInteger;
                        if (code === "confidence" && comp.valueInteger !== undefined)
                            goal.confidence = comp.valueInteger;
                    }
                    const notes = r.note ?? [];
                    if (notes[0])
                        goal.importance_note = notes[0].text;
                    if (notes[1])
                        goal.confidence_note = notes[1].text;
                }
                if (r.effectiveDateTime && !sessionDate)
                    sessionDate = r.effectiveDateTime.slice(0, 10);
            }
            else if (codeSystem === SNOMED_SYSTEM && codeCode === WHAT_MATTERS_CODE) {
                // MAP / Sense of Purpose observation. Most-recent-wins across notes.
                if (r.effectiveDateTime)
                    sessionDate = r.effectiveDateTime.slice(0, 10);
                if (r.valueString) {
                    const parsed = parseMapValueString(r.valueString);
                    if (parsed.map)
                        map = parsed.map;
                    if (parsed.what_matters_most)
                        what_matters_most = parsed.what_matters_most;
                }
            }
            else if (codeSystem === WBS_SYSTEM && codeCode === WBS_PANEL_CODE) {
                // WBS panel — last occurrence in the bundle is the most recent session.
                const wbsObj = {};
                if (r.effectiveDateTime) {
                    wbsObj.session_date = r.effectiveDateTime.slice(0, 10);
                    sessionDate = wbsObj.session_date;
                }
                for (const comp of r.component ?? []) {
                    const code = comp.code.coding?.[0]?.code;
                    if (code === "satisfied" && comp.valueInteger !== undefined)
                        wbsObj.satisfied = comp.valueInteger;
                    if (code === "involved" && comp.valueInteger !== undefined)
                        wbsObj.involved = comp.valueInteger;
                    if (code === "functioning" && comp.valueInteger !== undefined)
                        wbsObj.functioning = comp.valueInteger;
                }
                const scores = [wbsObj.satisfied, wbsObj.involved, wbsObj.functioning]
                    .filter((s) => s !== undefined);
                if (scores.length) {
                    wbsObj.average = Math.round((scores.reduce((a, b) => a + b, 0) / scores.length) * 100) / 100;
                }
                wbs = wbsObj;
            }
        }
        else if (r.resourceType === "ServiceRequest") {
            const goalUrl = r.extension?.find((e) => e.url === PERTAINSTOGOAL_URL)?.valueReference?.reference;
            const goalIdx = goalUrl !== undefined ? goalIdxByUrl.get(goalUrl) : undefined;
            if (goalIdx !== undefined) {
                const step = {
                    text: r.code?.text ?? "",
                    status: reverseStatus(r.status),
                    start_date: r.occurrencePeriod?.start?.slice(0, 10),
                    end_date: r.occurrencePeriod?.end?.slice(0, 10),
                };
                goals[goalIdx].action_steps.push(step);
            }
        }
    }
    return {
        patient,
        session_date: sessionDate,
        what_matters_most,
        map,
        values: [],
        vision: undefined,
        strengths: [],
        wbs,
        goals,
        is_final_session: false,
        discharge_plan: undefined,
    };
}
